import org.apache.commons.text.StringEscapeUtils;
import java.io.IOException;
import java.io.PrintWriter;

public class XSSFixedCode {

    public static void main(String[] args) {
        String userInput = "<script>alert('XSS Vulnerability!')</script>";

        // Properly escaping user input to prevent XSS attacks
        String escapedInput = StringEscapeUtils.escapeHtml4(userInput);
        String output = "<html><body>Hello, " + escapedInput + "</body></html>";

        try {
            PrintWriter writer = new PrintWriter("output.html", "UTF-8");
            writer.println(output);
            writer.close();
            System.out.println("Output file generated successfully.");
        } catch (IOException e) {
            System.out.println("Error writing output file: " + e.getMessage());
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
